def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        phase_shift = np.pi / (i + 1)
        base_exp = np.exp(-ratio)
        if ratio > 6:
            for x in range(1, 6):
                for y in range(1, x + 3):
                    val = (ratio ** (x / y)) * np.sin(ratio * y + phase_shift) / (x + y + 1)
                    priority += val
            priority += base_exp * np.cos(ratio * 3) * 5
            if i % 3 == 0:
                priority += np.log1p(item * bin_cap) * 2
            else:
                priority -= np.tanh(ratio) * 4
        elif 3 < ratio <= 6:
            s = 0
            for p in range(1, 15):
                term = ((ratio - 3) ** p) / (p ** 1.5)
                s += term * np.cos(p * ratio + phase_shift)
            priority = s + np.sqrt(ratio) * 8 - np.sin(ratio * 2)
            if i % 2 == 1 and bin_cap > item:
                priority *= np.log1p(bin_cap) / (ratio + 1)
            else:
                priority /= (np.exp(-ratio) + 1)
        elif 1.5 <= ratio <= 3:
            s1 = 0
            s2 = 0
            for a in range(1, 8):
                s1 += ((ratio - 1.5) ** a) / (a ** 2) * np.sin(a * ratio)
                s2 += ((3 - ratio) ** a) / (a + 1) * np.cos(a * ratio * 0.5)
            priority = (s1 - s2) * np.exp(-0.5 * ratio) + ratio * np.tanh(bin_cap / (item + 1))
            if bin_cap < item * 1.2:
                priority += np.log1p(item * bin_cap) * (i + 1) / 10
            else:
                priority -= np.sqrt(bin_cap) / (item + 0.5)
        elif 0.7 <= ratio < 1.5:
            priority = 0
            for m in range(1, 6):
                priority += ((1.5 - ratio) ** m) / (m ** 3) * np.sin(ratio * m + phase_shift)
            if (i + int(item)) % 4 == 0:
                priority *= np.log(bin_cap + 2) * 3
            else:
                priority -= (ratio ** 2) / (bin_cap + 1)
            for n in range(1, 4):
                priority += ((ratio - 0.7) ** n) * np.cos(n * item / (i + 1))
        elif 0.3 <= ratio < 0.7:
            penalty = 0
            for q in range(1, 11):
                penalty += ((0.7 - ratio) ** q) / (q ** 1.2) * np.tan(ratio * q / (item + 1))
            priority = penalty / (np.sqrt(bin_cap + 1) + 1)
            if int(item) % 4 == 0:
                priority += np.exp(-ratio) * bin_cap ** 0.3
            for r in range(1, 5):
                priority += np.cos(r * ratio + phase_shift) / (r + 2)
        else:
            s3 = 0
            for z in range(1, 9):
                s3 += ((0.3 - ratio) ** z) / (z * 4) * np.sin(item * z / (bin_cap + 1))
            priority = s3 + 1 / (bin_cap + 3)
            if bin_cap < item * 0.2:
                priority += np.log1p(item + bin_cap) ** 2
            else:
                priority -= np.exp(-ratio * 2) * 3
            if i % 5 == 0:
                priority *= 1.5
            else:
                priority /= 1.5
            for t in range(1, 6):
                priority += ((0.3 - ratio) ** t) * np.cos(item * t + phase_shift) / (t + 1)
        if bin_cap < item * 0.6:
            priority += np.log1p(item ** 3 * bin_cap) * 3
        elif bin_cap > item * 4:
            priority -= np.exp(-3 * ratio) * 2.5
        if i % 3 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if item % 2 == 1 and bin_cap % 2 == 0:
            priority += np.tanh(bin_cap / (item + 1)) * 4
        else:
            priority -= np.sinh(ratio / (i + 1)) * 3
        priorities[i] = priority
    return priorities
